6	function formatError(err: unknown): string {
7	  if (err instanceof Error) {
8	    return err.message;
9	  }
10	  return typeof err === "string" ? err : JSON.stringify(err);
11	}
12	
13	export async function probeIrc(
14	  cfg: CoreConfig,
15	  opts?: { accountId?: string; timeoutMs?: number },
16	): Promise<IrcProbe> {
17	  const account = resolveIrcAccount({ cfg, accountId: opts?.accountId });
18	  const base: IrcProbe = {
19	    ok: false,
20	    host: account.host,
21	    port: account.port,
22	    tls: account.tls,
23	    nick: account.nick,
24	  };
25	
26	  if (!account.configured) {
27	    return {
28	      ...base,
29	      error: "missing host or nick",
30	    };
31	  }
32	
33	  const started = Date.now();
34	  try {
35	    const client = await connectIrcClient(
36	      buildIrcConnectOptions(account, {
37	        connectTimeoutMs: opts?.timeoutMs ?? 8000,
38	      }),
39	    );
40	    const elapsed = Date.now() - started;
41	    client.quit("probe");
42	    return {
43	      ...base,
44	      ok: true,
45	      latencyMs: elapsed,
46	    };
47	  } catch (err) {
48	    return {
49	      ...base,
50	      error: formatError(err),
51	    };
52	  }
53	}
