// Inline meta (cannot use getChatChannelMeta since pulseboard is not in ChatChannelId)
const meta = {
  id: "pulseboard",
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Board URL + Token)",
  detailLabel: "PulseBoard",
  docsPath: "/channels/pulseboard",
  docsLabel: "pulseboard",
  blurb: "real-time bulletin board messaging with boards and DMs.",
  systemImage: "list.bullet.rectangle",
  order: 70,
  quickstartAllowFrom: true,
} as const;

export const pulseBoardPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: { ...meta },
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,            // PulseBoard: text-only (fictional)
      blockStreaming: true,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: PulseBoardChannelConfigSchema,
    config: { /* pulseBoardConfigAdapter */ },
    groups: { resolveRequireMention, resolveToolPolicy },
    messaging: {
      normalizeTarget: normalizePulseBoardMessagingTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<#board|userId>",
      },
    },
    resolver: { resolveTargets },
    directory: createChannelDirectoryAdapter({ listPeers, listGroups }),
    status: createComputedAccountStatusAdapter({ ... }),
    gateway: {
      startAccount: async (ctx) => {
        // Check configured, start monitor
        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () => await monitorPulseBoardProvider({ ... }),
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: normalizePulseBoardAllowEntry,
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard(id, message);
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
    collectWarnings: collectPulseBoardSecurityWarnings,
  },
  outbound: {
    base: {
      deliveryMode: "direct",
      chunker: chunkTextForOutbound,  // from local text-utils.ts
      chunkerMode: "markdown",
      textChunkLimit: 4000,           // PulseBoard's 4000 char limit
    },
    attachedResults: {
      channel: "pulseboard",
      sendText: async ({ cfg, to, text, accountId, replyToId }) =>
        await sendMessagePulseBoard(to, text, {
          cfg: cfg as CoreConfig,
          accountId: accountId ?? undefined,
          replyTo: replyToId ?? undefined,
        }),
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
        await sendMessagePulseBoard(
          to,
          mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
          { cfg: cfg as CoreConfig, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined }
        ),
    },
  },
});
