1	import { normalizeIrcAllowlist, resolveIrcAllowlistMatch } from "./normalize.js";
2	import type { IrcAccountConfig, IrcChannelConfig } from "./types.js";
3	import type { IrcInboundMessage } from "./types.js";
4	
5	export type IrcGroupMatch = {
6	  allowed: boolean;
7	  groupConfig?: IrcChannelConfig;
8	  wildcardConfig?: IrcChannelConfig;
9	  hasConfiguredGroups: boolean;
10	};
11	
12	export type IrcGroupAccessGate = {
13	  allowed: boolean;
14	  reason: string;
15	};
16	
17	export function resolveIrcGroupMatch(params: {
18	  groups?: Record<string, IrcChannelConfig>;
19	  target: string;
20	}): IrcGroupMatch {
21	  const groups = params.groups ?? {};
22	  const hasConfiguredGroups = Object.keys(groups).length > 0;
23	
24	  // IRC channel targets are case-insensitive, but config keys are plain strings.
25	  // To avoid surprising drops (e.g. "#TUIRC-DEV" vs "#tuirc-dev"), match
26	  // group config keys case-insensitively.
27	  const direct = groups[params.target];
28	  if (direct) {
29	    return {
30	      // "allowed" means the target matched an allowlisted key.
31	      // Explicit disables are handled later by resolveIrcGroupAccessGate.
32	      allowed: true,
33	      groupConfig: direct,
34	      wildcardConfig: groups["*"],
35	      hasConfiguredGroups,
36	    };
37	  }
38	
39	  const targetLower = params.target.toLowerCase();
40	  const directKey = Object.keys(groups).find((key) => key.toLowerCase() === targetLower);
41	  if (directKey) {
42	    const matched = groups[directKey];
43	    if (matched) {
44	      return {
45	        // "allowed" means the target matched an allowlisted key.
46	        // Explicit disables are handled later by resolveIrcGroupAccessGate.
47	        allowed: true,
48	        groupConfig: matched,
49	        wildcardConfig: groups["*"],
50	        hasConfiguredGroups,
51	      };
52	    }
53	  }
54	
55	  const wildcard = groups["*"];
56	  if (wildcard) {
57	    return {
58	      // "allowed" means the target matched an allowlisted key.
59	      // Explicit disables are handled later by resolveIrcGroupAccessGate.
60	      allowed: true,
61	      wildcardConfig: wildcard,
62	      hasConfiguredGroups,
63	    };
64	  }
65	  return {
66	    allowed: false,
67	    hasConfiguredGroups,
68	  };
69	}
70	
71	export function resolveIrcGroupAccessGate(params: {
72	  groupPolicy: IrcAccountConfig["groupPolicy"];
73	  groupMatch: IrcGroupMatch;
74	}): IrcGroupAccessGate {
75	  const policy = params.groupPolicy ?? "allowlist";
76	  if (policy === "disabled") {
77	    return { allowed: false, reason: "groupPolicy=disabled" };
78	  }
79	
80	  // In open mode, unconfigured channels are allowed (mention-gated) but explicit
81	  // per-channel/wildcard disables still apply.
82	  if (policy === "allowlist") {
83	    if (!params.groupMatch.hasConfiguredGroups) {
84	      return {
85	        allowed: false,
86	        reason: "groupPolicy=allowlist and no groups configured",
87	      };
88	    }
89	    if (!params.groupMatch.allowed) {
90	      return { allowed: false, reason: "not allowlisted" };
91	    }
92	  }
93	
94	  if (
95	    params.groupMatch.groupConfig?.enabled === false ||
96	    params.groupMatch.wildcardConfig?.enabled === false
97	  ) {
98	    return { allowed: false, reason: "disabled" };
