98	  applyAccountName: ({ cfg, accountId, name }) =>
99	    applyAccountNameToChannelSection({
100	      cfg,
101	      channelKey: channel,
102	      accountId,
103	      name,
104	    }),
105	  validateInput: createSetupInputPresenceValidator({
106	    whenNotUseEnv: [
107	      { someOf: ["host"], message: "IRC requires host." },
108	      { someOf: ["nick"], message: "IRC requires nick." },
109	    ],
110	  }),
111	  applyAccountConfig: ({ cfg, accountId, input }) => {
112	    const setupInput = input as IrcSetupInput;
113	    const namedConfig = applyAccountNameToChannelSection({
114	      cfg,
115	      channelKey: channel,
116	      accountId,
117	      name: setupInput.name,
118	    });
119	    const portInput =
120	      typeof setupInput.port === "number" ? String(setupInput.port) : String(setupInput.port ?? "");
121	    const patch: Partial<IrcAccountConfig> = {
122	      enabled: true,
123	      host: setupInput.host?.trim(),
124	      port: portInput ? parsePort(portInput, setupInput.tls === false ? 6667 : 6697) : undefined,
125	      tls: setupInput.tls,
126	      nick: setupInput.nick?.trim(),
127	      username: setupInput.username?.trim(),
128	      realname: setupInput.realname?.trim(),
129	      password: setupInput.password?.trim(),
130	      channels: setupInput.channels,
131	    };
132	    return patchScopedAccountConfig({
133	      cfg: namedConfig,
134	      channelKey: channel,
135	      accountId,
136	      patch,
137	    }) as CoreConfig;
138	  },
