80	  const actions: ChannelMessageActionName[] = [];
81	
82	  if (enabledAccounts.length > 0) {
83	    actions.push("send");
84	  }
85	
86	  const actionsConfig = cfg.channels?.mattermost?.actions as { reactions?: boolean } | undefined;
87	  const baseReactions = actionsConfig?.reactions;
88	  const hasReactionCapableAccount = enabledAccounts.some((account) => {
89	    const accountActions = account.config.actions as { reactions?: boolean } | undefined;
90	    return (accountActions?.reactions ?? baseReactions ?? true) !== false;
91	  });
92	  if (hasReactionCapableAccount) {
93	    actions.push("react");
94	  }
95	
96	  return {
97	    actions,
98	    capabilities: enabledAccounts.length > 0 ? ["buttons"] : [],
99	    schema:
100	      enabledAccounts.length > 0
101	        ? {
102	            properties: {
103	              buttons: Type.Optional(createMessageToolButtonsSchema()),
