39	export function chunkTextForOutbound(text: string, limit: number): string[] {
40	  const chunks: string[] = [];
41	  let remaining = text;
42	  while (remaining.length > limit) {
43	    const window = remaining.slice(0, limit);
44	    const splitAt = Math.max(window.lastIndexOf("\n"), window.lastIndexOf(" "));
45	    const breakAt = splitAt > 0 ? splitAt : limit;
46	    chunks.push(remaining.slice(0, breakAt).trimEnd());
47	    remaining = remaining.slice(breakAt).trimStart();
48	  }
49	  if (remaining.length > 0 || text.length === 0) {
50	    chunks.push(remaining);
51	  }
52	  return chunks;
53	}
