38	export function buildTimeoutAbortSignal(params: { timeoutMs?: number; signal?: AbortSignal }): {
39	  signal?: AbortSignal;
40	  cleanup: () => void;
41	} {
42	  const { timeoutMs, signal } = params;
43	  if (!timeoutMs && !signal) {
44	    return { signal: undefined, cleanup: () => {} };
45	  }
46	  if (!timeoutMs) {
47	    return { signal, cleanup: () => {} };
48	  }
49	
50	  const controller = new AbortController();
51	  const timeoutId = setTimeout(controller.abort.bind(controller), timeoutMs);
52	  const onAbort = () => controller.abort();
53	  if (signal) {
54	    if (signal.aborted) {
55	      controller.abort();
56	    } else {
57	      signal.addEventListener("abort", onAbort, { once: true });
58	    }
59	  }
60	
61	  return {
62	    signal: controller.signal,
63	    cleanup: () => {
64	      clearTimeout(timeoutId);
65	      signal?.removeEventListener("abort", onAbort);
66	    },
67	  };
68	}
