import type { DmPolicy, GroupPolicy } from "openclaw/plugin-sdk/setup";
import type { BaseProbeResult } from "openclaw/plugin-sdk/status-helpers";

export type { DmPolicy, GroupPolicy };

export type PulseBoardGroupConfig = {
  requireMention?: boolean;
  tools?: Record<string, unknown>;
  toolsBySender?: Record<string, Record<string, unknown>>;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard server URL (e.g. https://boards.example.com). */
  serverUrl?: string;
  /** API token for authenticating with the PulseBoard server. */
  apiToken?: string;
  /** File path containing the API token (alternative to inline config). */
  apiTokenFile?: string;
  /** Bot username on PulseBoard. */
  username?: string;
  /** Direct message policy (pairing/allowlist/open/disabled). */
  dmPolicy?: DmPolicy;
  /** Allowlist for direct messages (user ids). */
  allowFrom?: Array<string | number>;
  /** Group message policy (allowlist/open/disabled). */
  groupPolicy?: GroupPolicy;
  /** Allowlist for group messages (user ids). */
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration overrides. */
  boards?: Record<string, PulseBoardGroupConfig>;
  /** Boards to auto-subscribe on connect. */
  subscriptions?: string[];
  /** Outbound text chunk size (chars). Default: 4000. */
  textChunkLimit?: number;
  /** Chunking mode: "length" (default) splits by size; "newline" splits on every newline. */
  chunkMode?: "length" | "newline";
  /** Disable block streaming for this account. */
  blockStreaming?: boolean;
  /** Outbound response prefix override. */
  responsePrefix?: string;
  /** Maximum media attachment size in MB. */
  mediaMaxMb?: number;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

export type CoreConfig = {
  channels?: {
    pulseboard?: PulseBoardConfig;
    [key: string]: unknown;
  };
  commands?: { useAccessGroups?: boolean; [key: string]: unknown };
  session?: { store?: string; [key: string]: unknown };
  [key: string]: unknown;
};

export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation peer id: board name for groups, sender userId for DMs. */
  target: string;
  /** Sender user id on PulseBoard. */
  senderUserId: string;
  /** Display name of the sender. */
  senderDisplayName?: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  serverUrl: string;
  username: string;
  latencyMs?: number;
};

