/**
 * Split text into chunks suitable for PulseBoard outbound delivery.
 *
 * The default PulseBoard message limit is 4000 characters. This helper
 * splits on paragraph boundaries when possible, falling back to hard
 * character-limit splits so no chunk exceeds `limit`.
 */
export function chunkTextForOutbound(text: string, limit: number): string[] {
  if (!text) {
    return [];
  }
  if (text.length <= limit) {
    return [text];
  }

  const chunks: string[] = [];
  let remaining = text;

  while (remaining.length > 0) {
    if (remaining.length <= limit) {
      chunks.push(remaining);
      break;
    }

    // Try to split on a double-newline (paragraph boundary) near the limit.
    let splitIndex = remaining.lastIndexOf("\n\n", limit);
    if (splitIndex <= 0) {
      // Fall back to single newline.
      splitIndex = remaining.lastIndexOf("\n", limit);
    }
    if (splitIndex <= 0) {
      // Fall back to last space.
      splitIndex = remaining.lastIndexOf(" ", limit);
    }
    if (splitIndex <= 0) {
      // Hard split at the limit.
      splitIndex = limit;
    }

    chunks.push(remaining.slice(0, splitIndex).trimEnd());
    remaining = remaining.slice(splitIndex).trimStart();
  }

  return chunks.filter(Boolean);
}

