import {
  normalizePulseBoardAllowlist,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";
import type { PulseBoardAccountConfig, PulseBoardGroupConfig } from "./types.js";
import type { PulseBoardInboundMessage } from "./types.js";

export type PulseBoardGroupMatch = {
  allowed: boolean;
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
  hasConfiguredGroups: boolean;
};

export type PulseBoardGroupAccessGate = {
  allowed: boolean;
  reason: string;
};

export function resolvePulseBoardGroupMatch(params: {
  boards?: Record<string, PulseBoardGroupConfig>;
  target: string;
}): PulseBoardGroupMatch {
  const boards = params.boards ?? {};
  const hasConfiguredGroups = Object.keys(boards).length > 0;

  // Board targets are case-insensitive; match config keys accordingly.
  const direct = boards[params.target];
  if (direct) {
    return {
      allowed: true,
      groupConfig: direct,
      wildcardConfig: boards["*"],
      hasConfiguredGroups,
    };
  }

  const targetLower = params.target.toLowerCase();
  const directKey = Object.keys(boards).find((key) => key.toLowerCase() === targetLower);
  if (directKey) {
    const matched = boards[directKey];
    if (matched) {
      return {
        allowed: true,
        groupConfig: matched,
        wildcardConfig: boards["*"],
        hasConfiguredGroups,
      };
    }
  }

  const wildcard = boards["*"];
  if (wildcard) {
    return {
      allowed: true,
      wildcardConfig: wildcard,
      hasConfiguredGroups,
    };
  }
  return {
    allowed: false,
    hasConfiguredGroups,
  };
}

export function resolvePulseBoardGroupAccessGate(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  groupMatch: PulseBoardGroupMatch;
}): PulseBoardGroupAccessGate {
  const policy = params.groupPolicy ?? "allowlist";
  if (policy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }

  if (policy === "allowlist") {
    if (!params.groupMatch.hasConfiguredGroups) {
      return {
        allowed: false,
        reason: "groupPolicy=allowlist and no boards configured",
      };
    }
    if (!params.groupMatch.allowed) {
      return { allowed: false, reason: "not allowlisted" };
    }
  }

  if (
    params.groupMatch.groupConfig?.enabled === false ||
    params.groupMatch.wildcardConfig?.enabled === false
  ) {
    return { allowed: false, reason: "disabled" };
  }

  return { allowed: true, reason: policy === "open" ? "open" : "allowlisted" };
}

export function resolvePulseBoardRequireMention(params: {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
}): boolean {
  if (params.groupConfig?.requireMention !== undefined) {
    return params.groupConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  return true;
}

export function resolvePulseBoardMentionGate(params: {
  isGroup: boolean;
  requireMention: boolean;
  wasMentioned: boolean;
}): { shouldSkip: boolean; reason: string } {
  if (!params.isGroup) {
    return { shouldSkip: false, reason: "direct" };
  }
  if (!params.requireMention) {
    return { shouldSkip: false, reason: "mention-not-required" };
  }
  if (params.wasMentioned) {
    return { shouldSkip: false, reason: "mentioned" };
  }
  return { shouldSkip: true, reason: "missing-mention" };
}

export function resolvePulseBoardGroupSenderAllowed(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  message: PulseBoardInboundMessage;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  const policy = params.groupPolicy ?? "allowlist";
  const inner = normalizePulseBoardAllowlist(params.innerAllowFrom);
  const outer = normalizePulseBoardAllowlist(params.outerAllowFrom);

  if (inner.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: inner,
      senderId: params.message.senderUserId,
    }).allowed;
  }
  if (outer.length > 0) {
    return resolvePulseBoardAllowlistMatch({
      allowFrom: outer,
      senderId: params.message.senderUserId,
    }).allowed;
  }
  return policy === "open";
}

