/**
 * PulseBoard client stub.
 *
 * PulseBoard is a fictional platform. This module provides a minimal client
 * interface that logs operations but does not connect to any real server.
 * Replace this stub with a real WebSocket/REST client to integrate with an
 * actual PulseBoard server.
 */

export type PulseBoardClientOptions = {
  serverUrl: string;
  apiToken: string;
  username: string;
  subscriptions?: string[];
  abortSignal?: AbortSignal;
  onMessage?: (event: PulseBoardMessageEvent) => void | Promise<void>;
  onError?: (error: Error) => void;
  onConnected?: () => void;
};

export type PulseBoardMessageEvent = {
  messageId: string;
  boardId?: string;
  senderUserId: string;
  senderDisplayName?: string;
  text: string;
  timestamp: number;
  isDirect: boolean;
};

export type PulseBoardClient = {
  username: string;
  isReady: () => boolean;
  /** Post a message to a board or send a DM. */
  sendMessage: (target: string, text: string) => void;
  /** Subscribe to a named board. */
  subscribe: (board: string) => void;
  /** Disconnect from the PulseBoard server. */
  disconnect: (reason?: string) => void;
};

let messageCounter = 0;

/** Generate a unique message id for outbound PulseBoard messages. */
export function makePulseBoardMessageId(): string {
  messageCounter += 1;
  return `pb-${Date.now()}-${messageCounter}`;
}

/**
 * Create a stub PulseBoard client.
 *
 * In a real implementation this would open a WebSocket to the PulseBoard
 * server and authenticate with the provided API token.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  let ready = true;

  // Simulate a brief connection handshake.
  opts.onConnected?.();

  if (opts.subscriptions) {
    for (const board of opts.subscriptions) {
      // In a real client, this would send a SUBSCRIBE frame.
      void board;
    }
  }

  opts.abortSignal?.addEventListener(
    "abort",
    () => {
      ready = false;
    },
    { once: true },
  );

  return {
    username: opts.username,
    isReady: () => ready,
    sendMessage: (target: string, text: string) => {
      if (!ready) {
        throw new Error("PulseBoard client is not connected");
      }
      // Stub: in a real client, this would send to the server.
      void target;
      void text;
    },
    subscribe: (board: string) => {
      if (!ready) {
        throw new Error("PulseBoard client is not connected");
      }
      void board;
    },
    disconnect: (reason?: string) => {
      ready = false;
      void reason;
    },
  };
}

