  subscribe: (board: string) => void;
  /** Disconnect from the PulseBoard server. */
  disconnect: (reason?: string) => void;
};

let messageCounter = 0;

/** Generate a unique message id for outbound PulseBoard messages. */
export function makePulseBoardMessageId(): string {
  messageCounter += 1;
  return `pb-${Date.now()}-${messageCounter}`;
}

/**
 * Create a stub PulseBoard client.
 *
 * In a real implementation this would open a WebSocket to the PulseBoard
 * server and authenticate with the provided API token.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  let ready = true;

  // Simulate a brief connection handshake.
  opts.onConnected?.();

  if (opts.subscriptions) {
    for (const board of opts.subscriptions) {
      // In a real client, this would send a SUBSCRIBE frame.
      void board;
    }
  }

  opts.abortSignal?.addEventListener(
    "abort",
    () => {
      ready = false;
    },
    { once: true },
  );

  return {
    username: opts.username,
    isReady: () => ready,
    sendMessage: (target: string, text: string) => {
      if (!ready) {
        throw new Error("PulseBoard client is not connected");
      }
      // Stub: in a real client, this would send to the server.
      void target;
      void text;
    },
    subscribe: (board: string) => {
      if (!ready) {
        throw new Error("PulseBoard client is not connected");
      }
      void board;
    },
    disconnect: (reason?: string) => {
      ready = false;
      void reason;
    },
  };
}

