    send: async ({ text }) => {
      if (params.sendReply) {
        await params.sendReply(params.target, text);
      } else {
        await sendMessagePulseBoard(params.target, text, {
          accountId: params.accountId,
        });
      }
      params.statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}

export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  sendReply?: (target: string, text: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime, statusSink } = params;
  const core = getPulseBoardRuntime();

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  statusSink?.({ lastInboundAt: message.timestamp });

  const senderDisplay = message.senderDisplayName || message.senderUserId;

  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
  const { groupPolicy, providerMissingFallbackApplied } =
    resolveAllowlistProviderRuntimeGroupPolicy({
      providerConfigPresent: config.channels?.pulseboard !== undefined,
      groupPolicy: account.config.groupPolicy,
      defaultGroupPolicy,
    });
  warnMissingProviderGroupPolicyFallbackOnce({
    providerMissingFallbackApplied,
    providerKey: "pulseboard",
    accountId: account.accountId,
    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
    log: (msg) => runtime.log?.(msg),
  });

  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);
  const configGroupAllowFrom = normalizePulseBoardAllowlist(account.config.groupAllowFrom);

  const groupMatch = resolvePulseBoardGroupMatch({
    boards: account.config.boards,
    target: message.target,
  });

  // Gate group messages against group policy.
  if (message.isGroup) {
    const groupAccess = resolvePulseBoardGroupAccessGate({ groupPolicy, groupMatch });
    if (!groupAccess.allowed) {
      runtime.log?.(`pulseboard: drop board ${message.target} (${groupAccess.reason})`);
      return;
    }
  }

  const directGroupAllowFrom = normalizePulseBoardAllowlist(groupMatch.groupConfig?.allowFrom);
  const wildcardGroupAllowFrom = normalizePulseBoardAllowlist(groupMatch.wildcardConfig?.allowFrom);
  const groupAllowFrom =
    directGroupAllowFrom.length > 0 ? directGroupAllowFrom : wildcardGroupAllowFrom;

  // Gate group senders against allowlists.
  if (message.isGroup) {
    const senderAllowed = resolvePulseBoardGroupSenderAllowed({
      groupPolicy,
      message,
      outerAllowFrom: configGroupAllowFrom,
      innerAllowFrom: groupAllowFrom,
    });
    if (!senderAllowed) {
      runtime.log?.(`pulseboard: drop group sender ${senderDisplay} (policy=${groupPolicy})`);
      return;
    }
  } else {
    // Gate DMs.
    if (dmPolicy === "disabled") {
      runtime.log?.(`pulseboard: drop DM sender=${senderDisplay} (dmPolicy=disabled)`);
      return;
    }
    if (dmPolicy !== "open") {
      const dmAllowed = resolvePulseBoardAllowlistMatch({
        allowFrom: configAllowFrom,
        senderId: message.senderUserId,
      }).allowed;
      if (!dmAllowed) {
        logInboundDrop({
          log: (line) => runtime.log?.(line),
          channel: CHANNEL_ID,
          reason: `dmPolicy=${dmPolicy}`,
          target: senderDisplay,
        });
        return;
      }
    }
  }

  // Mention gating for group messages.
  const mentionRegexes = core.channel.mentions.buildMentionRegexes(config as OpenClawConfig);
  const explicitMentionRegex = account.username
    ? new RegExp(`@${account.username.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i")
    : null;
  const wasMentioned =
    core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes) ||
    (explicitMentionRegex ? explicitMentionRegex.test(rawBody) : false);

  const requireMention = message.isGroup
    ? resolvePulseBoardRequireMention({
        groupConfig: groupMatch.groupConfig,
        wildcardConfig: groupMatch.wildcardConfig,
      })
    : false;

  const mentionGate = resolvePulseBoardMentionGate({
    isGroup: message.isGroup,
    requireMention,
    wasMentioned,
  });
  if (mentionGate.shouldSkip) {
    runtime.log?.(`pulseboard: drop board ${message.target} (${mentionGate.reason})`);
    return;
  }

  // Resolve agent routing and build the inbound envelope.
  const peerId = message.isGroup ? message.target : message.senderUserId;
  const route = core.channel.routing.resolveAgentRoute({
    cfg: config as OpenClawConfig,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    peer: {
      kind: message.isGroup ? "group" : "direct",
      id: peerId,
    },
  });

  const fromLabel = message.isGroup ? message.target : senderDisplay;
  const storePath = core.channel.session.resolveStorePath(config.session?.store, {
    agentId: route.agentId,
  });
  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(config as OpenClawConfig);
  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });
  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: fromLabel,
    timestamp: message.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const groupSystemPrompt = groupMatch.groupConfig?.systemPrompt?.trim() || undefined;

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: message.isGroup ? `pulseboard:board:${message.target}` : `pulseboard:${senderDisplay}`,
    To: `pulseboard:${peerId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: message.isGroup ? "group" : "direct",
    ConversationLabel: fromLabel,
    SenderName: message.senderDisplayName || undefined,
    SenderId: message.senderUserId,
    GroupSubject: message.isGroup ? message.target : undefined,
    GroupSystemPrompt: message.isGroup ? groupSystemPrompt : undefined,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    WasMentioned: message.isGroup ? wasMentioned : undefined,
    MessageSid: message.messageId,
    Timestamp: message.timestamp,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: `pulseboard:${peerId}`,
    CommandAuthorized: false,
  });

  // Dispatch the reply through the agent pipeline.
  const replyRequest = core.channel.reply.buildReplyRequest({
    cfg: config as OpenClawConfig,
    channel: CHANNEL_ID,
    route,
    storePath,
    ctxPayload,
  });

  await core.channel.reply.dispatchAndDeliver({
    replyRequest,
    deliver: async (payload) => {
      await deliverPulseBoardReply({
        payload,
        target: peerId,
        accountId: account.accountId,
        sendReply: params.sendReply,
        statusSink,
      });
    },
  });
}

