import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { connectPulseBoardClient, makePulseBoardMessageId, type PulseBoardClient } from "./client.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { isBoardTarget } from "./normalize.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage, client: PulseBoardClient) => void | Promise<void>;
};

export function resolvePulseBoardInboundTarget(params: {
  boardId?: string;
  senderUserId: string;
  isDirect: boolean;
}): {
  isGroup: boolean;
  target: string;
} {
  if (!params.isDirect && params.boardId) {
    return { isGroup: true, target: params.boardId };
  }
  return { isGroup: false, target: params.senderUserId };
}

export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need serverUrl and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let client: PulseBoardClient | null = null;

  client = await connectPulseBoardClient({
    serverUrl: account.serverUrl,
    apiToken: account.apiToken,
    username: account.username,
    subscriptions: (account.config.subscriptions ?? []).filter(
      (sub) => isBoardTarget(sub) || sub.startsWith("#"),
    ),
    abortSignal: opts.abortSignal,
    onError: (error) => {
      logger.error(`[${account.accountId}] PulseBoard error: ${error.message}`);
    },
    onMessage: async (event) => {
      if (!client) {
        return;
      }
      // Skip messages from ourselves.
      if (event.senderUserId.toLowerCase() === client.username.toLowerCase()) {
        return;
      }

      const inboundTarget = resolvePulseBoardInboundTarget({
        boardId: event.boardId,
        senderUserId: event.senderUserId,
        isDirect: event.isDirect,
      });
      const message: PulseBoardInboundMessage = {
        messageId: event.messageId || makePulseBoardMessageId(),
        target: inboundTarget.target,
        senderUserId: event.senderUserId,
        senderDisplayName: event.senderDisplayName,
        text: event.text,
        timestamp: event.timestamp || Date.now(),
        isGroup: inboundTarget.isGroup,
      };

      core.channel.activity.record({
        channel: "pulseboard",
        accountId: account.accountId,
        direction: "inbound",
        at: message.timestamp,
      });

      if (opts.onMessage) {
        await opts.onMessage(message, client);
        return;
      }

      await handlePulseBoardInbound({
        message,
        account,
        config: cfg,
        runtime,
        sendReply: async (target, text) => {
          client?.sendMessage(target, text);
          opts.statusSink?.({ lastOutboundAt: Date.now() });
          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "outbound",
          });
        },
        statusSink: opts.statusSink,
      });
    },
  });

  logger.info(
    `[${account.accountId}] connected to PulseBoard at ${account.serverUrl} as ${client.username}`,
  );

  return {
    stop: () => {
      client?.disconnect("shutdown");
      client = null;
    },
  };
}

