          const boards = resolvedAfterGroups.config.boards ?? {};
          const patched = Object.fromEntries(
            Object.entries(boards).map(([key, value]) => [
              key,
              { ...value, requireMention: false },
            ]),
          );
          next = updatePulseBoardAccountConfig(next, accountId, { boards: patched });
        }
      }
    }

